import{c as o,Q as n,j as a,m as r}from"./chunks/framework.DpF7k2f3.js";const d=JSON.parse('{"title":"제4장 Python과 엔지니어링 기초","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ko/part2-fundamentals/chapter4.md","filePath":"ko/part2-fundamentals/chapter4.md"}'),e={name:"ko/part2-fundamentals/chapter4.md"};function s(p,t,l,i,c,h){return n(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="제4장-python과-엔지니어링-기초" tabindex="-1">제4장 Python과 엔지니어링 기초 <a class="header-anchor" href="#제4장-python과-엔지니어링-기초" aria-label="Permalink to &quot;제4장 Python과 엔지니어링 기초&quot;">​</a></h1><p>##本章에서 배울 것들</p><p>&quot;진짜 실전&quot; 기초편에 오신 것을 환영합니다!</p><p>来到这里之前,你可能看过一些Python教程——变量、数据类型、循环、関数、&quot;零基础小白&quot;용. 내용은 문제없지만,这种感觉是否 있습니까: 学完之后还是不知道这跟AI开发有什么关系?</p><p>이것이 제가 해결하려는 핵심 문제입니다.</p><p><strong>이 챕터는 Python 입문이 아니라 Python의 &quot;AI 개발 크래시 코스&quot;입니다.</strong> 변수가 무엇인지教えない(你已经知道), <code>if-else</code> 작성方法도教えない(你已经见过). 무엇을 가르칠까요: AI 회사에서第一天上班时打开代码编辑器, 那些让你头皮发麻的东西到底是什么.</p><p>이 챕터를 읽고 나면 가져갈 것들:</p><ul><li><strong>dataclass/pydantic</strong> 사용 시나리오 - 왜 AI 코드에 이것들로 가득 찬지</li><li><strong>asyncio</strong> 비동기 프로그래밍 실전 패턴 - 배치 API 호출의 필수 기술</li><li><strong>타입 힌트</strong>의 올바른用法 - Copilot이 정말 도와주게 하는 방법</li><li><strong>견고한 HTTP 클라이언트</strong> 래핑 - LLM API 호출의 스트리밍, 재시도, 타임아웃</li><li><strong>Git 워크플로우</strong>의 올바른 자세 - monorepo, pre-commit, .env 보안</li><li><strong>2026년 환경 관리 솔루션</strong> - uv가 왜 이렇게 핫한지</li><li><strong>GPU 서버 생존 기술</strong> - 로그 확인, 프로세스 확인, 리소스 디버깅</li></ul><hr><blockquote><p><strong>전체 번역은 곧 제공될 예정입니다. 지금은中文版을 읽으실 수 있습니다.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part2-fundamentals/chapter4.html">中文版阅读</a></p></blockquote>',10)])])}const m=o(e,[["render",s]]);export{d as __pageData,m as default};
